def icon(name, color=None):
    """
    Get an SVG icon by name, optionally with a custom color.
    
    Args:
        name: Icon name from ICONS dictionary
        color: Optional color to replace 'currentColor' in the SVG
        
    Returns:
        SVG string with optional color replacement
    """
    svg = ICONS.get(name, "")
    if color:
        svg = svg.replace('stroke="currentColor"', f'stroke="{color}"')
    return svg
